fn bench_render_cycle(c: &mut Criterion) {
    let mut group = c.benchmark_group("render_cycle");

    // Note: Can't benchmark actual terminal output, but can benchmark
    // everything up to that point

    group.bench_function("prepare_frame_80x24", |b| {
        let mut front = OptimizedBuffer::new(80, 24);
        let mut back = OptimizedBuffer::new(80, 24);

        b.iter(|| {
            // Simulate drawing
            back.clear(Rgba::from_rgb_u8(20, 20, 30));
            back.draw_text(10, 5, "Hello, World!", Style::default());
            back.draw_box(5, 3, 70, 18, BoxStyle::double());

            // Calculate diff
            let diff = BufferDiff::compute(&front, &back);

            // Swap buffers
            std::mem::swap(&mut front, &mut back);

            black_box(diff);
        })
    });

    group.finish();
}
```

